+func TestFinalizeDurableAudit_TrackerLockTimeoutIsTransientNotOperatorAttention(t *testing.T) {
+	timeoutErr := fmt.Errorf("commit durable audit outputs: %w", &TrackerLockTimeoutError{
+		Why:      "max elapsed",
+		LockDir:  "/repo/.ddx/.git-tracker.lock",
+		OwnerPID: "424293",
+	})
+	result, sink := runAuditWithFinalizeErrAndEvents(t, timeoutErr)
+
+	require.Nil(t, result.OperatorAttention, "tracker-lock timeout during audit commit must not stop the worker")
+	assert.NotEqual(t, "operator_attention", result.ExitReason)
+
+	var sawTransient bool
+	for _, event := range sink.events() {
+		if event["type"] != "loop.durable_audit_transient" {
+			continue
+		}
+		sawTransient = true
+		data, ok := event["data"].(map[string]any)
+		require.True(t, ok, "durable audit transient event must include data")
+		assert.Equal(t, "ddx-audit-lock", data["bead_id"])
+		assert.Contains(t, fmt.Sprint(data["detail"]), "tracker lock timeout")
+	}
+	assert.True(t, sawTransient, "tracker-lock timeout must emit durable_audit_transient")
+}
